/**
 * event
 * @name setOdrWrkPathStepDetailMultisortTimeout
 * @description
 */
scwin.setOdrWrkPathStepDetailMultisortTimeout = async function (row, dontSetBroadcast) {
  if (row < 0) {
    row = 0;
  }
  //multisort를 setJSON이후에 바로 실행하면 적용되지 않는다.
  $c.util.setTimeout($p, () => {
    ds_odrWrkPathStepDetail.multisort({
      sortIndex: "odrNo cntrSeq odrWrkPathSeq odrWrkStpSeq",
      sortOrder: "1 1 1 1"
    });
    if (!dontSetBroadcast) {
      ds_odrWrkPathStepDetail.setBroadcast(true, true);
    }
    gr_odrWrkPathStepDetail.setFocusedCell(row, gr_odrWrkPathStepDetail.getFocusedColumnID() ?? "dptWrkPlNm", false);
    // 작업단계 추가 가능여부 확인 및 행삽입, 행삭제, 취소 버튼 관리
    scwin.f_checkWorkStepEditMode(row);
    console.log("scwin.setOdrWrkPathStepDetailMultisortTimeout gr_odrWrkPathStepDetail.setFocusedCell");
  }, {
    delay: 50
  });
};

