/**
 * event
 * @name gr_odrWrkPathStepDetail_onviewchange
 * @description
 */
scwin.gr_odrWrkPathStepDetail_onviewchange = function (info) {
  const row = info.rowIndex;
  let rowObj = ds_odrWrkPathStepDetail.getRowJSON(row);
  let pName = info.newValue;
  let pOrgName = info.oldValue;
  let colid = info.colId;
  switch (colid) {
    case "wrkLobranNm":
      if (pName != "" && pName != pOrgName) {
        ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranCd", "");
        ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNm", "");
        scwin.f_openCommPopUpGrid(1, row, '', pName, 'T', 'T');
      }
      break;
    case "dptWrkPlNm":
      if (pName != "" && pName != pOrgName) {
        ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlCd", "");
        ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlNm", "");
        scwin.f_openCommPopUpGrid(2, row, '', pName, 'T', 'T');
      }
      break;
    case "internalSellLodeptNm":
      if (pName != "" && pName != pOrgName) {
        ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptCd", "");
        ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNm", "");
        scwin.f_openCommPopUpGrid(3, row, '', pName, 'T', 'T');
      }
      break;
    case "wrkPlClsCd":
      // 작업장 구분
      // 작업장구분이 변경될때 작업단계로 Filter 처리
      scwin.setLkStepNoChkColumnFilter(row);
      if (info.newValue != ds_odrWrkPathStepDetail.getOriginalCellData(row, colid)) {
        ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlCd", "");
        ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlNm", "");
      }

      // 추가된 작업단계의 작업장 구분이 운송인 경우 매출입항목을 운송료로, 운송이 아닌경우 무매출로 설정한다.
      if (rowObj.odrWrkStpSeq % 10 != 0) {
        // 작업단계순번을 10으로 나눈 나머지가 0이 아닌 경우 - 추가된 작업단계
        if ($c.gus.cfIsNull($p, info.newValue.trim())) {
          // 운송 단계인 경우
          ds_odrWrkPathStepDetail.setCellData(row, "selpchItemCd", DsConstants.SELL_ITEM_CD_TRANS_RATE);
          ds_odrWrkPathStepDetail.setCellData(row, "selpchItemNm", "운송료");
        } else {
          // 운송 단계가 아닌 경우
          ds_odrWrkPathStepDetail.setCellData(row, "selpchItemCd", SdConstants.SELPCH_ITEM_CD_NOSELL);
          ds_odrWrkPathStepDetail.setCellData(row, "selpchItemNm", "무매출");
        }
      }
      break;
    case "wrkStpCd":
      // 작업단계
      break;
    default:
      break;
  }
};

